SELECT EXISTS(
    SELECT 1
    FROM bank_account
    WHERE user_id = #{userId}
      AND bank_code = #{bankCode}
      AND account_number = #{accountNumber}
      AND deleted_at IS NULL
)

SELECT id, user_id, bank_code, account_number, account_holder_name, registered_at, deleted_at
FROM bank_account
WHERE id = #{id}
  AND user_id = #{userId}
  AND deleted_at IS NULL

mapper.update:
UPDATE bank_account
   SET deleted_at = NOW()
WHERE id = #{id}
  AND user_id = #{userId}
  AND deleted_at IS NULL
